SELECT source_name
FROM interrupt_sources
WHERE active = 1;

SELECT COUNT(*) AS active_interrupt_count
FROM interrupts
WHERE active = 1;

SELECT priority_level
FROM interrupt_priorities
WHERE priority_id = 1;

SELECT priority_level
FROM interrupt_priorities
WHERE system_critical = 1;

SELECT interrupt_id, MAX(triggered_at) AS latest_triggered_time
FROM interrupt_logs
GROUP BY interrupt_id;

SELECT MAX(triggered_at) AS latest_triggered_at
FROM interrupt_logs
WHERE source_id = 1;

SELECT COUNT(*) AS active_sources
FROM interrupt_sources
WHERE active = 1;

SELECT MAX(last_reset_time)
  FROM interrupt_sources
  WHERE active = 1;

SELECT details
FROM interrupt_logs
WHERE interrupt_id = 1;

SELECT COUNT(*) AS log_count
FROM interrupt_logs
WHERE source_id = 1;
